/**
 * Standalone type definitions that were previously generated by drizzle-orm
 * from the PlanetScale database schema. These types are now maintained manually
 * and match the Convex schema shapes.
 */

export interface Comment {
  id: number;
  content: string;
  eventId: string;
  userId: string;
  createdAt: Date;
  updatedAt: Date | null;
}

export interface Event {
  id: string;
  userId: string;
  userName: string;
  event: unknown;
  eventMetadata: unknown;
  startDateTime: Date;
  endDateTime: Date;
  visibility: "public" | "private";
  createdAt: Date;
  updatedAt: Date | null;
}

export interface EventFollow {
  userId: string;
  eventId: string;
}

export interface ListFollow {
  userId: string;
  listId: string;
}

export interface UserFollow {
  followerId: string;
  followingId: string;
}

export interface List {
  id: string;
  userId: string;
  name: string;
  description: string;
  visibility: "public" | "unlisted" | "private";
  createdAt: Date;
  updatedAt: Date | null;
}

export interface User {
  id: string;
  username: string;
  email: string;
  displayName: string;
  userImage: string;
  bio: string | null;
  publicEmail: string | null;
  publicPhone: string | null;
  publicInsta: string | null;
  publicWebsite: string | null;
  publicMetadata: unknown;
  emoji: string | null;
  onboardingData: unknown;
  onboardingCompletedAt: Date | null;
  createdAt: Date;
  updatedAt: Date | null;
}

export interface EventToLists {
  eventId: string;
  listId: string;
}

export interface UserPublicMetadata {
  stripe?: {
    customerId?: string;
  };
  plan?: {
    name?: string;
    productId?: string;
    status?: string;
    id?: string;
  };
  showDiscover?: boolean;
}

export interface OnboardingData {
  notificationsEnabled?: boolean;
  ageRange?: "Under 24" | "25-34" | "35-44" | "45-54" | "55-64" | "65+";
  source?:
    | "Google Search"
    | "TikTok"
    | "Searched on App Store"
    | "Instagram"
    | "Facebook"
    | "Through a friend"
    | "Other";
  discoveryMethod?:
    | "Instagram"
    | "TikTok"
    | "Friends' recommendations"
    | "Local websites/newsletters"
    | "Walking around town"
    | "Facebook";
  screenshotEvents?: "Yes" | "Not yet";
  goals?: string[];
  /**
   * @deprecated Use `goals` instead. Kept for backward compatibility.
   */
  priority?: {
    text: string;
    emoji: string;
  };
  completedAt?: string;
  watchedDemo?: boolean;
  subscribed?: boolean;
  subscribedAt?: string;
  subscriptionPlan?: string;
  trialMode?: boolean;
  trialStartedAt?: string;
}
